export const BUCKETS = ["1-10", "11-20", "21-30", "31-40", "40+"];

export function bucketForRank(r) {
  if (r <= 10) return "1-10";
  if (r <= 20) return "11-20";
  if (r <= 30) return "21-30";
  if (r <= 40) return "31-40";
  return "40+"; // 41 through the very last ranked player
}

// Players grouped into the five buckets, in rank order.
export function playersByBucket() {
  const out = { "1-10": [], "11-20": [], "21-30": [], "31-40": [], "40+": [] };
  for (const p of OWGR_RANKINGS) out[bucketForRank(p.rank)].push(p);
  return out;
}

// Stable, name-based key used as the pick id and as the player-DB key.
export const slug = (name) =>
  (name || "").normalize("NFKD").replace(/[\u0300-\u036f]/g, "")
    .toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");

// A pick object вЂ” what we store on an entry and feed to the leaderboard.
export const toPick = (p) => ({
  key: slug(p.name), name: p.name, owgr: p.rank, bucket: bucketForRank(p.rank), flag: p.flag,
});

// Player DB keyed by slug вЂ” drop-in replacement for the old hardcoded `P`.
export const OWGR_PLAYERS = Object.fromEntries(
  OWGR_RANKINGS.map((p) => [slug(p.name),
    { name: p.name, owgr: p.rank, bucket: bucketForRank(p.rank), flag: p.flag }])
);

// Dropdown options grouped by bucket, in rank order.
export function bucketOptions() {
  const g = playersByBucket();
  const out = {};
  for (const b of BUCKETS) out[b] = g[b].map(toPick);
  return out;
}
